"date_jp": "<ruby>一月<rt>いちがつ</rt></ruby><ruby>六日<rt>むいか</rt></ruby>（<ruby>火曜日<rt>かようび</rt></ruby>）",
"date_fr": "Mardi six Janvier",
"lunar": "冬月十八",
"en_q": "The secret of getting ahead is getting started.",
"en_cn": "领先的秘诀在于开始。",
"jp_q": "<ruby>急<rt>いそ</rt></ruby>がば<ruby>回<rt>まわ</rt></ruby>れ。",
