"date": "2026-01-10",
"week_cn": "星期六",
"date_jp": "<ruby>一月<rt>いちがつ</rt></ruby><ruby>十日<rt>とおか</rt></ruby>（<ruby>土曜日<rt>どようび</rt></ruby>）",
